using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Keep the old name so existing documents are readable and
            // direct SQL queries (WHERE c.Discriminator = …) keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — id value format changed.
            // EF Core 8 generated id as "Product|123"; EF Core 9 uses just "123".
            // We add the legacy shadow property so reads find existing docs and
            // new writes stay compatible with the old format.
            entity.Property<string>("__id")
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex throws on Cosmos in EF Core 9.
            // Removed the previous HasIndex(p => p.Sku) call.
            // Cosmos DB indexing is managed via the container's indexing policy.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

